import{_ as d,C as i,o as s,c,ai as l,E as a,w as o,a as r}from"./chunks/framework.BH_J6TYN.js";const f=JSON.parse('{"title":"¿Qué es SYNTIcat?","description":"Catálogo digital con carrito de compras y checkout por WhatsApp para tiendas venezolanas","frontmatter":{"title":"¿Qué es SYNTIcat?","description":"Catálogo digital con carrito de compras y checkout por WhatsApp para tiendas venezolanas"},"headers":[],"relativePath":"cat/que-es-synticat.md","filePath":"cat/que-es-synticat.md"}'),p={name:"cat/que-es-synticat.md"};function u(g,t,h,m,b,q){const e=i("Step"),n=i("Steps");return s(),c("div",null,[t[5]||(t[5]=l('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p>SYNTIcat es el producto de SYNTIweb para <strong>tiendas de ropa, proveedores, comercios con catálogo y retail venezolano</strong>. Te da un catálogo visual profesional donde tus clientes ven los productos con fotos, variantes (talla, color), los agregan al carrito y te envían el pedido completo por WhatsApp. En el plan Anual, cada pedido tiene un código de seguimiento tipo <code>SC-XXXX</code>.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p>Para crear un SYNTIcat nuevo: <code>syntiweb.com/onboarding</code> → <strong>&quot;Catálogo de Productos&quot;</strong> → Asistente de 5 pasos.</p><p>Tu catálogo queda en <code>tunegocio.syntiweb.com</code>.</p><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><ul><li><strong>Catálogo visual</strong> con tarjetas de productos: foto, nombre, precio, badge</li><li><strong>Variantes</strong> por producto: talla, color, talla+color, opciones libres (según plan)</li><li><strong>Carrito de compras</strong> (plan Semestral+): Tu cliente agrega productos y revisa antes de enviar</li><li><strong>Mini Order</strong> con código <code>SC-XXXX</code> (plan Anual): Cada pedido tiene un ID rastreable</li><li><strong>Checkout por WhatsApp</strong>: El carrito se envía como mensaje estructurado a tu WhatsApp</li><li><strong>Badges de producto</strong>: 🆕 Nuevo, 🔥 Hot, 💰 Promo</li><li><strong>Múltiples imágenes</strong> por producto (hasta 6 en plan Anual)</li></ul><h3 id="flujo-de-compra-del-cliente" tabindex="-1">Flujo de compra del cliente <a class="header-anchor" href="#flujo-de-compra-del-cliente" aria-label="Permalink to &quot;Flujo de compra del cliente&quot;">​</a></h3>',8)),a(n,null,{default:o(()=>[a(e,{title:"Navega el catálogo"},{default:o(()=>[...t[0]||(t[0]=[r(" Ve las tarjetas de productos con foto, nombre, precio y badge. ",-1)])]),_:1}),a(e,{title:"Selecciona un producto"},{default:o(()=>[...t[1]||(t[1]=[r(" Elige variantes (talla, color) si las tiene. ",-1)])]),_:1}),a(e,{title:"Agrega al carrito (Semestral+)"},{default:o(()=>[...t[2]||(t[2]=[r(" En plan Básico → botón directo a WhatsApp. En Semestral/Anual → se agrega al carrito. ",-1)])]),_:1}),a(e,{title:"Revisa el carrito"},{default:o(()=>[...t[3]||(t[3]=[r(" Ve el resumen: productos, variantes, cantidades y total. ",-1)])]),_:1}),a(e,{title:"Envía por WhatsApp"},{default:o(()=>[...t[4]||(t[4]=[r(" Se abre WhatsApp con el pedido completo. En plan Anual incluye código SC-XXXX. ",-1)])]),_:1})]),_:1}),t[6]||(t[6]=l('<h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li><strong>No procesa pagos</strong> — el pago se coordina por WhatsApp</li><li><strong>No tiene pasarela de pago</strong> (Stripe, PayPal, etc.)</li><li><strong>No maneja inventario</strong> — no descuenta stock automáticamente</li><li><strong>No tiene wishlist</strong> ni favoritos</li><li><strong>No tiene búsqueda</strong> ni filtros en el catálogo</li><li><strong>No tiene categorías</strong> de productos (grid plano)</li><li><strong>No tiene reseñas</strong> de productos</li><li><strong>No calcula envío</strong> ni tiene integración con delivery</li></ul><h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Básico (REF 9/mes)</th><th>Semestral (REF 39)</th><th>Anual (REF 69/año) ⭐</th></tr></thead><tbody><tr><td>Productos</td><td>20</td><td>100</td><td>Ilimitados</td></tr><tr><td>Imágenes por producto</td><td>1</td><td>3</td><td>6</td></tr><tr><td>Variantes</td><td>Solo simple (sin variantes)</td><td>Talla + talla/color</td><td>Todas + opciones libres</td></tr><tr><td>Carrito</td><td>❌ (solo botón WA directo)</td><td>✅ Carrito básico</td><td>✅ Carrito completo</td></tr><tr><td>Código de orden SC-XXXX</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td>Mini Order (JSON guardado)</td><td>❌</td><td>❌</td><td>✅</td></tr></tbody></table><h2 id="compite-con" tabindex="-1">Compite con... <a class="header-anchor" href="#compite-con" aria-label="Permalink to &quot;Compite con...&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Alternativa</th><th>Precio</th><th>Lo que le falta vs SYNTIcat</th></tr></thead><tbody><tr><td>Cattaly</td><td>REF 97/año</td><td>Sin carrito de compras</td></tr><tr><td>Instagram Shopping</td><td>Gratis</td><td>Sin catálogo profesional, sin carrito</td></tr><tr><td><strong>SYNTIcat Anual</strong></td><td><strong>REF 69/año</strong></td><td>Todo incluido + carrito + Mini Order</td></tr></tbody></table><h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-tienda-de-ropa-moda-urbana-en-caracas" tabindex="-1">Caso: Tienda de ropa &quot;Moda Urbana&quot; en Caracas <a class="header-anchor" href="#caso-tienda-de-ropa-moda-urbana-en-caracas" aria-label="Permalink to &quot;Caso: Tienda de ropa &quot;Moda Urbana&quot; en Caracas&quot;">​</a></h3><p>Sofía tiene una tienda de ropa con plan Anual:</p><ol><li>Sube productos: &quot;Camisa polo&quot; (REF 15, tallas S/M/L/XL, colores negro/blanco/azul)</li><li>Sube &quot;Jeans clásico&quot; (REF 25, tallas 28-36), &quot;Gorra deportiva&quot; (REF 8)</li><li>Marca &quot;Camisa polo&quot; con badge 🔥 Hot</li></ol><p>Un cliente entra al catálogo desde Instagram:</p><ul><li>Ve la camisa polo → elige talla M, color azul → &quot;Agregar al carrito&quot;</li><li>Ve los jeans → elige talla 30 → &quot;Agregar al carrito&quot;</li><li>Abre el carrito → ve el resumen</li><li>Toca &quot;Enviar pedido&quot; → WhatsApp se abre con el pedido completo y código SC-0047</li></ul><p>Sofía recibe el pedido, confirma disponibilidad y coordina pago y envío por WhatsApp.</p><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/cat/carrito-whatsapp.html">Carrito y WhatsApp</a> — Cómo funciona el carrito → WhatsApp</li><li><a href="/cat/mini-order-sc.html">Mini Order (SC-XXXX)</a> — Códigos de seguimiento de pedidos</li><li><a href="/cat/catalogo-productos.html">Catálogo de productos</a> — Cómo administrar tu catálogo</li></ul>',15))])}const C=d(p,[["render",u]]);export{f as __pageData,C as default};
